var primary = GetColor(parameters, "mainColor", System.Windows.Media.Colors.White);
        var r = primary.R / 255f;
        var g = primary.G / 255f;
        var b = primary.B / 255f;
        var a = GetFloat(parameters, "opacity", 1f);
        var pattern = GetChoice(parameters, "pattern", "solid");
        var spacing = GetFloat(parameters, "patternSpacing", 0.25f);
        var secondary = GetColor(parameters, "secondaryColor", System.Windows.Media.Color.FromRgb(51, 51, 51));
        var r2 = secondary.R / 255f;
        var g2 = secondary.G / 255f;
        var b2 = secondary.B / 255f;

        var size = context.TileSize;

        // Try GPU accelerated path first when available

        if (pattern == "solid")
            return PixelBuffer.CreateSolid(size, size, r, g, b, a);

        var buffer = new PixelBuffer(size, size);
        var cellPixels = Math.Max(1, (int)(spacing * size));

        buffer.ParallelForEachPixel((x, y) =>
        {
            bool useSecondary;
            switch (pattern)
            {
                case "checkerboard":
                    useSecondary = ((x / cellPixels) + (y / cellPixels)) % 2 == 1;
                    break;
                case "stripesHorizontal":
                    useSecondary = (y / cellPixels) % 2 == 1;
                    break;
                case "stripesVertical":
                    useSecondary = (x / cellPixels) % 2 == 1;
                    break;
                default:
                    useSecondary = false;
                    break;
            }

            if (useSecondary)
                buffer.SetPixel(x, y, r2, g2, b2, a);
            else
                buffer.SetPixel(x, y, r, g, b, a);
        });

        return buffer;
}
